sys_script_include.script:
var CertificateRenewService = Class.create();
CertificateRenewService.prototype = {
	initialize: function () {
		this.httpRequestUtils = new HttpRequestUtils();
		this.glideRecordUtils = new GlideRecordUtils();
		this.certificateService = new CertificateService();
		this.logger = new Logger('CertificateRenewService');
	},

	fetchCertificates: function () {
		this.logger.info("fetchCertificates(): started");

		var gr = new GlideRecord(Constants.CERTIFICATE.table);
		gr.query();
		var result = [];
		var profiles = this.fetchProfiles();
		var count = 0;
		while (gr.next()) {
			var isNotificationSent = gr.getValue('renewal_notification_status');

			if (isNotificationSent === '0') {
				var certificateProfileId = gr.getValue('profile_id');
				var certificateSerialNumber = gr.getValue('serial_number');
				var certificateSysId = gr.getValue('sys_id');
				var seatId = gr.getValue('seat_id');
				var validTo = gr.getValue('valid_to');
				var renewalPeriodDays = profiles[certificateProfileId];

				if (renewalPeriodDays) {

					var expirationTime = this.convertTime(validTo);
					var renewalBeginTime = this.subtractDuration(validTo, renewalPeriodDays);
					var currentTime = new GlideDateTime();


					if (currentTime > renewalBeginTime && currentTime < expirationTime) {
						this.logger.info('fetchCertificates(): renewal email sent for certificate with serial number : ' + certificateSerialNumber);
						gs.eventQueue(Constants.EVENT.renewCertificate, gr, seatId);
						count++;
						gr.renewal_notification_status = true;
						gr.update();
						result.push({
							certificateSerialNumber: certificateSerialNumber,
							certificateProfileId: certificateProfileId,
							isNotificationSent: isNotificationSent,
							certificateSysId: certificateSysId,
							seatId: seatId,
							validTo: validTo
						});

					}

				}
				else {
					this.logger.info('fetchCertificates(): notification has not been sent as no profile available for cert with : SERIAL NUM' + certificateSerialNumber);
				}

			}
		}
		this.logger.info('fetchCertificates(): total number of notification sent: ' + count);
		this.logger.info("fetchCertificates(): ended");
		return result;
	},

	fetchProfiles: function () {
		var gr = new GlideRecord(Constants.PROFILE.table);
		gr.query();

		var result = {};
		while (gr.next()) {
			var profileId = gr.getValue('id');
			var renewalPeriodDays = gr.getValue('renewal_period_days');

			result[profileId] = renewalPeriodDays;

		}

		return result;

	},

	convertTime: function (dateString) {
		var isoDateString = dateString.replace('Z', '');
		var gdt = new GlideDateTime(isoDateString);
		return gdt;
	},

	subtractDuration: function (dateString, renewalDays) {
		var isoDateString = dateString.replace('Z', '');
		var gdt = new GlideDateTime(isoDateString);
		var duration = new GlideDuration(renewalDays * 24 * 60 * 60 * 1000);
		gdt.subtract(duration);
		return gdt;
	},

	resenRenewalEmail: function (certificateSysId,adminComment) {
		var gr = new GlideRecord(Constants.CERTIFICATE.table);
		if (gr.get(certificateSysId)) {
			var seatId = gr.getValue('seat_id');
			gs.eventQueue(Constants.EVENT.renewCertificate, gr, seatId);
			gr.renewal_notification_status = true;
			gr.renewal_comment = adminComment;
			gr.update();
			this.logger.debug(
				'resenRenewalEmail(): Renewal email triggered again for cert sys_id {0}',
				certificateSysId);
		}
	},
	type: 'CertificateRenewService',
};
